import{_ as i,o as t,c as a,aj as s}from"./chunks/framework.DEEoir6m.js";const h=JSON.parse('{"title":"Community","description":"Join the GISPulse community — GitHub, discussions, contributing, roadmap.","frontmatter":{"title":"Community","description":"Join the GISPulse community — GitHub, discussions, contributing, roadmap."},"headers":[],"relativePath":"en/community.md","filePath":"en/community.md"}'),o={name:"en/community.md"};function r(n,e,l,u,c,d){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h1><p>GISPulse is built in the open. Whether you are a GIS analyst, a data engineer, or a spatial developer, there are many ways to get involved.</p><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><p>The source code, issues, and discussions all live on GitHub:</p><ul><li><strong>Repository:</strong> <a href="https://github.com/imagodata/gispulse" target="_blank" rel="noreferrer">github.com/imagodata/gispulse</a></li><li><strong>Stars and forks</strong> are appreciated — they help others discover the project.</li></ul><h2 id="discussions" tabindex="-1">Discussions <a class="header-anchor" href="#discussions" aria-label="Permalink to &quot;Discussions&quot;">​</a></h2><p>Have a question, an idea, or want to share how you use GISPulse?</p><ul><li><a href="https://github.com/imagodata/gispulse/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> is the place for open conversations.</li><li>Categories: Q&amp;A, Ideas, Show and Tell, General.</li><li>Please search existing discussions before creating a new one.</li></ul><h2 id="issues" tabindex="-1">Issues <a class="header-anchor" href="#issues" aria-label="Permalink to &quot;Issues&quot;">​</a></h2><p>Found a bug or want to request a feature?</p><ul><li><a href="https://github.com/imagodata/gispulse/issues/new" target="_blank" rel="noreferrer">Open an issue</a> with a clear description.</li><li>For bugs: include your GISPulse version, Python version, OS, and steps to reproduce.</li><li>For features: describe the use case and why existing capabilities do not cover it.</li></ul><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>We welcome contributions of all kinds: code, documentation, bug reports, and ideas.</p><ul><li>Read the <a href="/gispulse/en/contributing">Contributing Guide</a> to get started.</li><li>First-time contributors: look for issues labeled <code>good first issue</code>.</li><li>All contributions go through pull requests with code review.</li></ul><h2 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h2><p>Technical articles, release announcements, and deep dives into spatial processing:</p><ul><li><a href="/gispulse/blog/gispulse-vs-fme">GISPulse Blog</a></li><li>Topics: rules-as-config patterns, engine benchmarks, use case walkthroughs, migration guides.</li></ul><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><ul><li><strong>General inquiries:</strong> <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a></li><li><strong>Sales &amp; Enterprise:</strong> <a href="mailto:sales@gispulse.dev" target="_blank" rel="noreferrer">sales@gispulse.dev</a></li><li><strong>Security issues:</strong> <a href="mailto:security@gispulse.dev" target="_blank" rel="noreferrer">security@gispulse.dev</a> (please do not open public issues for security vulnerabilities)</li></ul><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h2><p>GISPulse follows a public roadmap driven by community feedback and production needs:</p><ul><li><strong>Short term</strong> — Stability, test coverage, documentation</li><li><strong>Medium term</strong> — Additional capabilities (validation, topology), template marketplace, improved portal UX</li><li><strong>Long term</strong> — Horizontal scaling, cloud-native deployment, STAC integration, advanced raster processing</li></ul><p>The roadmap is shaped by real user needs. <a href="https://github.com/imagodata/gispulse/discussions" target="_blank" rel="noreferrer">Share your priorities</a> to influence what comes next.</p><h2 id="sponsors" tabindex="-1">Sponsors <a class="header-anchor" href="#sponsors" aria-label="Permalink to &quot;Sponsors&quot;">​</a></h2><p>GISPulse is an independent open-source project. If your organization benefits from GISPulse, consider supporting its development:</p><ul><li><strong>Pro/Team/Enterprise subscriptions</strong> directly fund development</li><li><strong>Sponsorship opportunities</strong> — contact <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a></li><li><strong>In-kind contributions</strong> — testing, documentation, translations, and advocacy all help</li></ul><p>Every contribution, large or small, helps keep GISPulse independent and sustainable.</p>',27)])])}const g=i(o,[["render",r]]);export{h as __pageData,g as default};
